357	FZ_NORETURN void (fz_throw)(fz_context *ctx, int code, const char *fmt, ...)
358	{
359		va_list ap;
360		va_start(ap, fmt);
361		fz_vthrow(ctx, code, fmt, ap);
362		/* va_end(ap); // unreachable */
363	}
