372	void (fz_morph_error)(fz_context *ctx, int fromerr, int toerr)
373	{
374		assert(ctx && ctx->error.errcode >= FZ_ERROR_NONE);
375		if (ctx->error.errcode == fromerr)
376			ctx->error.errcode = toerr;
377	}
