529	
530	void fz_report_error(fz_context *ctx)
531	{
532	#ifdef CLUSTER
533		if (ctx->error.errcode == FZ_ERROR_TRYLATER || ctx->error.errcode == FZ_ERROR_ABORT)
534		{
535			fprintf(stderr, "REPORTED ERROR THAT IS TRYLATER OR ABORT\n");
536			abort();
537		}
538	#endif
539		/* TODO: send errcode to fz_log_error instead of formatting it here */
540		fz_log_error_printf(ctx, "%s error: %s", fz_error_type_name(ctx->error.errcode), ctx->error.message);
541		ctx->error.errcode = FZ_ERROR_NONE;
542	}
543	
544	void fz_ignore_error(fz_context *ctx)
545	{
546	#ifdef CLUSTER
547		if (ctx->error.errcode != FZ_ERROR_TRYLATER && ctx->error.errcode != FZ_ERROR_ABORT)
548		{
549			fprintf(stderr, "IGNORED ERROR THAT IS NOT TRYLATER OR ABORT\n");
550			abort();
551		}
552	#endif
553		ctx->error.errcode = FZ_ERROR_NONE;
554	}
555	
556	/* Convert an error into another runtime exception. */
557	const char *fz_convert_error(fz_context *ctx, int *code)
558	{
559		if (code)
560			*code = ctx->error.errcode;
561		ctx->error.errcode = FZ_ERROR_NONE;
562		return ctx->error.message;
563	}
